# Filtering, Sorting, and Sparse Fieldsets

Giving API consumers control over which data they receive and how it is ordered is essential for building flexible, performant APIs. This lesson covers the three main data-shaping mechanisms: filtering, sorting, and field selection.

## Filtering

Filtering lets clients request only the records they need.

### Simple Equality Filters

```
GET /api/posts?status=published&authorId=42
```

```typescript
app.get('/api/posts', async (req, res) => {
  const allowedFilters = ['status', 'authorId', 'category'];
  const where: Record<string, any> = {};

  for (const key of allowedFilters) {
    if (req.query[key] !== undefined) {
      where[key] = req.query[key];
    }
  }

  const posts = await prisma.post.findMany({ where });
  res.json({ data: posts });
});
```

### Operator-Based Filters

For more complex queries, use operators in query parameters:

```
GET /api/products?price[gte]=10&price[lte]=100&rating[gt]=4
GET /api/posts?createdAt[after]=2024-01-01&title[contains]=javascript
```

```typescript
interface FilterOperators {
  eq?: any;
  neq?: any;
  gt?: number;
  gte?: number;
  lt?: number;
  lte?: number;
  contains?: string;
  startsWith?: string;
  in?: any[];
}

function parseFilters(query: Record<string, any>): Record<string, any> {
  const prismaWhere: Record<string, any> = {};

  for (const [key, value] of Object.entries(query)) {
    // Handle operator syntax: field[operator]=value
    const match = key.match(/^(\w+)\[(\w+)\]$/);
    if (match) {
      const [, field, operator] = match;
      if (!prismaWhere[field]) prismaWhere[field] = {};

      switch (operator) {
        case 'eq': prismaWhere[field].equals = value; break;
        case 'neq': prismaWhere[field].not = value; break;
        case 'gt': prismaWhere[field].gt = Number(value); break;
        case 'gte': prismaWhere[field].gte = Number(value); break;
        case 'lt': prismaWhere[field].lt = Number(value); break;
        case 'lte': prismaWhere[field].lte = Number(value); break;
        case 'contains': prismaWhere[field].contains = value; break;
        case 'startsWith': prismaWhere[field].startsWith = value; break;
        case 'in': prismaWhere[field].in = value.split(','); break;
      }
    } else if (typeof value === 'string' && !key.startsWith('sort') && key !== 'fields' && key !== 'page' && key !== 'limit') {
      // Simple equality
      prismaWhere[key] = value;
    }
  }

  return prismaWhere;
}

app.get('/api/products', async (req, res) => {
  const where = parseFilters(req.query as Record<string, any>);
  const products = await prisma.product.findMany({ where });
  res.json({ data: products });
});
```

### Full-Text Search Filter

```
GET /api/posts?q=javascript+async
```

```typescript
app.get('/api/posts', async (req, res) => {
  const searchQuery = req.query.q as string;

  if (searchQuery) {
    // PostgreSQL full-text search via Prisma raw query
    const posts = await prisma.$queryRaw`
      SELECT * FROM posts
      WHERE to_tsvector('english', title || ' ' || body)
        @@ plainto_tsquery('english', ${searchQuery})
      ORDER BY ts_rank(
        to_tsvector('english', title || ' ' || body),
        plainto_tsquery('english', ${searchQuery})
      ) DESC
      LIMIT 20
    `;
    return res.json({ data: posts });
  }

  const posts = await prisma.post.findMany({ take: 20 });
  res.json({ data: posts });
});
```

## Sorting

Allow clients to control the order of results.

```
GET /api/posts?sort=createdAt       (ascending)
GET /api/posts?sort=-createdAt      (descending, prefix with -)
GET /api/posts?sort=-createdAt,title (multi-field sort)
```

```typescript
function parseSortParam(sort: string | undefined, allowedFields: string[]): Record<string, 'asc' | 'desc'>[] {
  if (!sort) return [{ createdAt: 'desc' }]; // default sort

  return sort.split(',').map(field => {
    const direction = field.startsWith('-') ? 'desc' : 'asc';
    const fieldName = field.replace(/^-/, '');

    // Security: only allow sorting on approved fields
    if (!allowedFields.includes(fieldName)) {
      throw new Error(`Cannot sort by '${fieldName}'. Allowed: ${allowedFields.join(', ')}`);
    }

    return { [fieldName]: direction };
  });
}

app.get('/api/posts', async (req, res) => {
  const allowedSortFields = ['createdAt', 'title', 'viewCount', 'likeCount'];

  try {
    const orderBy = parseSortParam(req.query.sort as string, allowedSortFields);
    const posts = await prisma.post.findMany({ orderBy, take: 20 });
    res.json({ data: posts });
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
});
```

### JSON:API Style Sorting

The JSON:API spec uses exactly this convention with comma-separated fields and `-` prefix for descending. It is a well-understood standard.

## Sparse Fieldsets (Field Selection)

Let clients request only the fields they need, reducing bandwidth and improving performance.

```
GET /api/posts?fields=id,title,createdAt
GET /api/users?fields=id,name,avatar
```

```typescript
function parseFields(fields: string | undefined, allowedFields: string[]): Record<string, boolean> | undefined {
  if (!fields) return undefined; // return all fields

  const requested = fields.split(',').map(f => f.trim());
  const select: Record<string, boolean> = {};

  for (const field of requested) {
    if (allowedFields.includes(field)) {
      select[field] = true;
    }
  }

  // Always include id
  select.id = true;

  return select;
}

app.get('/api/posts', async (req, res) => {
  const allowedFields = ['id', 'title', 'body', 'status', 'createdAt', 'updatedAt', 'authorId'];
  const select = parseFields(req.query.fields as string, allowedFields);

  const posts = await prisma.post.findMany({
    ...(select && { select }),
    take: 20,
  });

  res.json({ data: posts });
});
```

### Nested Field Selection

For APIs with relationships:

```
GET /api/posts?fields=id,title&fields[author]=id,name
```

```typescript
function parseNestedFields(query: Record<string, any>): any {
  const select: Record<string, any> = {};

  // Top-level fields
  if (query.fields && typeof query.fields === 'string') {
    for (const f of query.fields.split(',')) {
      select[f.trim()] = true;
    }
  }

  // Nested fields: fields[relation]=field1,field2
  for (const [key, value] of Object.entries(query)) {
    const match = key.match(/^fields\[(\w+)\]$/);
    if (match && typeof value === 'string') {
      const relation = match[1];
      const relationFields: Record<string, boolean> = {};
      for (const f of value.split(',')) {
        relationFields[f.trim()] = true;
      }
      select[relation] = { select: relationFields };
    }
  }

  return Object.keys(select).length > 0 ? select : undefined;
}
```

## Combining Everything: A Reusable Query Builder

```typescript
import { Request } from 'express';

interface QueryOptions {
  allowedFilters: string[];
  allowedSorts: string[];
  allowedFields: string[];
  defaultSort: string;
  maxLimit: number;
}

function buildQuery(req: Request, options: QueryOptions) {
  const page = Math.max(1, parseInt(req.query.page as string) || 1);
  const limit = Math.min(
    options.maxLimit,
    Math.max(1, parseInt(req.query.limit as string) || 20)
  );

  return {
    where: parseFilters(req.query as Record<string, any>),
    orderBy: parseSortParam(req.query.sort as string || options.defaultSort, options.allowedSorts),
    select: parseFields(req.query.fields as string, options.allowedFields),
    skip: (page - 1) * limit,
    take: limit,
  };
}

// Usage
app.get('/api/products', async (req, res) => {
  const query = buildQuery(req, {
    allowedFilters: ['category', 'status', 'price', 'brand'],
    allowedSorts: ['price', 'createdAt', 'name', 'rating'],
    allowedFields: ['id', 'name', 'price', 'category', 'description', 'rating', 'imageUrl'],
    defaultSort: '-createdAt',
    maxLimit: 100,
  });

  const [products, total] = await Promise.all([
    prisma.product.findMany(query),
    prisma.product.count({ where: query.where }),
  ]);

  res.json({ data: products, pagination: { page, limit, total } });
});
```

## Security Considerations

1. **Always whitelist filterable/sortable fields.** Never pass user input directly to the query.
2. **Validate filter values.** A price filter should be numeric, a status filter should be an enum.
3. **Limit complexity.** Cap the number of simultaneous filters, sort fields, and selected fields.
4. **Beware of SQL injection.** When building raw queries, always use parameterized queries.
5. **Rate limit expensive queries.** Sorting by non-indexed fields or using `contains` on large text columns is expensive.

```typescript
// Zod schema for query validation
import { z } from 'zod';

const productQuerySchema = z.object({
  page: z.coerce.number().int().min(1).default(1),
  limit: z.coerce.number().int().min(1).max(100).default(20),
  sort: z.string().optional(),
  fields: z.string().optional(),
  status: z.enum(['active', 'draft', 'archived']).optional(),
  'price[gte]': z.coerce.number().optional(),
  'price[lte]': z.coerce.number().optional(),
  q: z.string().max(200).optional(),
});
```

5.1.5.body:
# Standardized Error Responses (RFC 7807)

Inconsistent error responses are one of the most common API design failures. RFC 7807 (Problem Details for HTTP APIs) defines a standard format that makes errors machine-readable and developer-friendly.

## The Problem with Ad-Hoc Errors

Without a standard, every endpoint returns errors differently:

```json
// Endpoint A
{ "error": "Not found" }

// Endpoint B
{ "message": "User not found", "code": 404 }

// Endpoint C
{ "errors": [{ "msg": "Invalid email", "field": "email" }] }

// Endpoint D
"Something went wrong"
```

Clients cannot reliably parse errors, write generic error handlers, or provide good user feedback.

## RFC 7807: Problem Details

The standard defines these fields:

```typescript
interface ProblemDetails {
  type: string;       // URI identifying the error type (default: "about:blank")
  title: string;      // Short, human-readable summary
  status: number;     // HTTP status code
  detail?: string;    // Human-readable explanation specific to this occurrence
  instance?: string;  // URI reference identifying this specific occurrence
  [key: string]: any; // Extension fields
}
```

Example:

```json
{
  "type": "https://api.example.com/errors/insufficient-funds",
  "title": "Insufficient Funds",
  "status": 422,
  "detail": "Your account balance of $10.00 is insufficient for the $25.00 purchase.",
  "instance": "/transactions/abc123",
  "balance": 10.00,
  "required": 25.00
}
```

The `Content-Type` should be `application/problem+json`.

## Implementation in Express

```typescript
// errors/problem-details.ts
export class ProblemDetails extends Error {
  public readonly type: string;
  public readonly title: string;
  public readonly status: number;
  public readonly detail?: string;
  public readonly instance?: string;
  public readonly extensions: Record<string, any>;

  constructor(opts: {
    type?: string;
    title: string;
    status: number;
    detail?: string;
    instance?: string;
    extensions?: Record<string, any>;
  }) {
    super(opts.title);
    this.type = opts.type || 'about:blank';
    this.title = opts.title;
    this.status = opts.status;
    this.detail = opts.detail;
    this.instance = opts.instance;
    this.extensions = opts.extensions || {};
  }

  toJSON() {
    return {
      type: this.type,
      title: this.title,
      status: this.status,
      ...(this.detail && { detail: this.detail }),
      ...(this.instance && { instance: this.instance }),
      ...this.extensions,
    };
  }
}

// Predefined error factories
export const Errors = {
  notFound: (resource: string, id: string | number) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/not-found',
      title: 'Resource Not Found',
      status: 404,
      detail: `${resource} with id '${id}' was not found.`,
      instance: `/api/${resource.toLowerCase()}s/${id}`,
    }),

  validationFailed: (errors: Array<{ field: string; message: string }>) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/validation-failed',
      title: 'Validation Failed',
      status: 422,
      detail: 'One or more fields failed validation.',
      extensions: { errors },
    }),

  unauthorized: (detail?: string) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/unauthorized',
      title: 'Unauthorized',
      status: 401,
      detail: detail || 'Authentication is required to access this resource.',
    }),

  forbidden: (detail?: string) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/forbidden',
      title: 'Forbidden',
      status: 403,
      detail: detail || 'You do not have permission to perform this action.',
    }),

  conflict: (detail: string) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/conflict',
      title: 'Conflict',
      status: 409,
      detail,
    }),

  rateLimited: (retryAfter: number) =>
    new ProblemDetails({
      type: 'https://api.example.com/errors/rate-limited',
      title: 'Too Many Requests',
      status: 429,
      detail: 'You have exceeded the rate limit.',
      extensions: { retryAfter },
    }),
};
```

### Error Handling Middleware

```typescript
import { Request, Response, NextFunction } from 'express';

function errorHandler(err: Error, req: Request, res: Response, next: NextFunction) {
  // If it's already a ProblemDetails, send it
  if (err instanceof ProblemDetails) {
    return res
      .status(err.status)
      .type('application/problem+json')
      .json(err.toJSON());
  }

  // Handle Zod validation errors
  if (err.name === 'ZodError') {
    const zodErr = err as any;
    const problem = Errors.validationFailed(
      zodErr.issues.map((issue: any) => ({
        field: issue.path.join('.'),
        message: issue.message,
      }))
    );
    return res
      .status(problem.status)
      .type('application/problem+json')
      .json(problem.toJSON());
  }

  // Handle Prisma errors
  if (err.constructor.name === 'PrismaClientKnownRequestError') {
    const prismaErr = err as any;
    if (prismaErr.code === 'P2002') {
      const fields = prismaErr.meta?.target?.join(', ');
      const problem = Errors.conflict(
        `A record with this ${fields} already exists.`
      );
      return res.status(409).type('application/problem+json').json(problem.toJSON());
    }
    if (prismaErr.code === 'P2025') {
      const problem = Errors.notFound('Record', 'unknown');
      return res.status(404).type('application/problem+json').json(problem.toJSON());
    }
  }

  // Generic 500 error (never expose stack traces in production)
  console.error('Unhandled error:', err);
  const problem = new ProblemDetails({
    type: 'https://api.example.com/errors/internal',
    title: 'Internal Server Error',
    status: 500,
    detail: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred.'
      : err.message,
  });

  res.status(500).type('application/problem+json').json(problem.toJSON());
}

// Register as last middleware
app.use(errorHandler);
```

### Using in Routes

```typescript
app.get('/api/users/:id', async (req, res, next) => {
  try {
    const user = await prisma.user.findUnique({
      where: { id: parseInt(req.params.id) },
    });

    if (!user) {
      throw Errors.notFound('User', req.params.id);
    }

    res.json({ data: user });
  } catch (err) {
    next(err);
  }
});

app.post('/api/users', async (req, res, next) => {
  try {
    const result = userSchema.safeParse(req.body);
    if (!result.success) {
      throw Errors.validationFailed(
        result.error.issues.map(i => ({
          field: i.path.join('.'),
          message: i.message,
        }))
      );
    }

    const user = await prisma.user.create({ data: result.data });
    res.status(201).json({ data: user });
  } catch (err) {
    next(err);
  }
});
```

## NestJS Implementation

NestJS has built-in exception filters that can be customized:

```typescript
import { ExceptionFilter, Catch, ArgumentsHost, HttpException } from '@nestjs/common';

@Catch()
export class ProblemDetailsFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse();
    const request = ctx.getRequest();

    let problem: any;

    if (exception instanceof ProblemDetails) {
      problem = exception.toJSON();
    } else if (exception instanceof HttpException) {
      const status = exception.getStatus();
      const exResponse = exception.getResponse();
      problem = {
        type: 'about:blank',
        title: typeof exResponse === 'string' ? exResponse : (exResponse as any).error,
        status,
        detail: typeof exResponse === 'string' ? exResponse : (exResponse as any).message,
        instance: request.url,
      };
    } else {
      problem = {
        type: 'https://api.example.com/errors/internal',
        title: 'Internal Server Error',
        status: 500,
        detail: 'An unexpected error occurred.',
        instance: request.url,
      };
    }

    response
      .status(problem.status)
      .header('Content-Type', 'application/problem+json')
      .json(problem);
  }
}

// Register globally in main.ts
app.useGlobalFilters(new ProblemDetailsFilter());
```

## Validation Error Format

For validation errors, include a structured `errors` array:

```json
{
  "type": "https://api.example.com/errors/validation-failed",
  "title": "Validation Failed",
  "status": 422,
  "detail": "One or more fields failed validation.",
  "errors": [
    {
      "field": "email",
      "message": "Must be a valid email address"
    },
    {
      "field": "password",
      "message": "Must be at least 8 characters"
    },
    {
      "field": "age",
      "message": "Must be a positive integer"
    }
  ]
}
```

## Error Type Registry

Maintain a page/document listing all your error types:

```
https://api.example.com/errors/not-found
https://api.example.com/errors/validation-failed
https://api.example.com/errors/unauthorized
https://api.example.com/errors/forbidden
https://api.example.com/errors/conflict
https://api.example.com/errors/rate-limited
https://api.example.com/errors/insufficient-funds
```

Each URI should resolve to a human-readable page explaining the error, possible causes, and how to fix it.

5.2.1.body:
# GraphQL Fundamentals: Schema, Queries, and Mutations

GraphQL is a query language for APIs that lets clients request exactly the data they need. Unlike REST, where the server determines the response shape, GraphQL puts the client in control.

## Why GraphQL?

REST has fundamental limitations for complex UIs:

```
REST: Multiple requests for one screen
+--------+     GET /users/1         +--------+
| Client | -----------------------> | Server |
|        |     GET /users/1/posts   |        |
|        | -----------------------> |        |
|        |     GET /posts/5/comments|        |
|        | -----------------------> |        |
+--------+                          +--------+
  3 round trips, over-fetching on each

GraphQL: One request for exactly what you need
+--------+     POST /graphql        +--------+
| Client | -----------------------> | Server |
|        |     { user, posts,       |        |
|        |       comments }         |        |
+--------+                          +--------+
  1 round trip, exact data
```

## Schema Definition Language (SDL)

GraphQL APIs are defined by a schema using SDL:

```graphql
# Types define the shape of data
type User {
  id: ID!
  email: String!
  name: String!
  bio: String
  posts: [Post!]!
  createdAt: DateTime!
}

type Post {
  id: ID!
  title: String!
  body: String!
  published: Boolean!
  author: User!
  comments: [Comment!]!
  tags: [String!]!
  createdAt: DateTime!
  updatedAt: DateTime!
}

type Comment {
  id: ID!
  text: String!
  author: User!
  post: Post!
  createdAt: DateTime!
}

# Custom scalar
scalar DateTime

# Enums
enum PostStatus {
  DRAFT
  PUBLISHED
  ARCHIVED
}

# Input types for mutations
input CreatePostInput {
  title: String!
  body: String!
  tags: [String!]
  status: PostStatus = DRAFT
}

input UpdatePostInput {
  title: String
  body: String
  tags: [String!]
  status: PostStatus
}

# Query type: read operations
type Query {
  user(id: ID!): User
  users(limit: Int = 20, offset: Int = 0): [User!]!
  post(id: ID!): Post
  posts(
    limit: Int = 20
    offset: Int = 0
    status: PostStatus
    authorId: ID
  ): [Post!]!
  searchPosts(query: String!): [Post!]!
}

# Mutation type: write operations
type Mutation {
  createUser(email: String!, name: String!, bio: String): User!
  createPost(input: CreatePostInput!): Post!
  updatePost(id: ID!, input: UpdatePostInput!): Post!
  deletePost(id: ID!): Boolean!
  addComment(postId: ID!, text: String!): Comment!
}
```

### Key SDL Concepts

- `!` means non-nullable (field is guaranteed to have a value)
- `[Post!]!` means a non-nullable array of non-nullable Posts
- `ID` is a special scalar type for identifiers
- `input` types are used for mutation arguments
- Default values: `limit: Int = 20`

## Setting Up Apollo Server

```typescript
import { ApolloServer } from '@apollo/server';
import { expressMiddleware } from '@apollo/server/express4';
import express from 'express';
import { readFileSync } from 'fs';

// Load schema from .graphql file
const typeDefs = readFileSync('./schema.graphql', 'utf-8');

// Or define inline
const typeDefs = `#graphql
  type Query {
    hello: String!
  }
`;

// Resolvers implement the schema
const resolvers = {
  Query: {
    hello: () => 'Hello, GraphQL!',
  },
};

async function startServer() {
  const app = express();
  const server = new ApolloServer({ typeDefs, resolvers });
  await server.start();

  app.use('/graphql', express.json(), expressMiddleware(server));
  app.listen(4000, () => console.log('Server running on port 4000'));
}

startServer();
```

## Writing Queries

Clients send queries to request specific fields:

```graphql
# Basic query
query {
  users {
    id
    name
    email
  }
}

# Query with arguments
query {
  user(id: "1") {
    name
    posts {
      title
      createdAt
    }
  }
}

# Query with variables (recommended for production)
query GetUser($userId: ID!) {
  user(id: $userId) {
    name
    email
    posts(status: PUBLISHED) {
      title
      body
      comments {
        text
        author {
          name
        }
      }
    }
  }
}
# Variables: { "userId": "1" }
```

### Aliases and Fragments

```graphql
# Aliases: query the same field with different arguments
query {
  publishedPosts: posts(status: PUBLISHED, limit: 5) {
    ...PostFields
  }
  draftPosts: posts(status: DRAFT, limit: 5) {
    ...PostFields
  }
}

# Fragment: reusable field selection
fragment PostFields on Post {
  id
  title
  createdAt
  author {
    name
  }
}
```

## Writing Mutations

```graphql
mutation CreatePost($input: CreatePostInput!) {
  createPost(input: $input) {
    id
    title
    status
    author {
      name
    }
  }
}
# Variables:
# {
#   "input": {
#     "title": "GraphQL Fundamentals",
#     "body": "Learn GraphQL from scratch...",
#     "tags": ["graphql", "api"],
#     "status": "DRAFT"
#   }
# }
```

## Implementing Resolvers

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

const resolvers = {
  Query: {
    users: async (_parent, args) => {
      return prisma.user.findMany({
        take: args.limit,
        skip: args.offset,
      });
    },

    user: async (_parent, args) => {
      return prisma.user.findUnique({ where: { id: args.id } });
    },

    posts: async (_parent, args) => {
      const where: any = {};
      if (args.status) where.status = args.status;
      if (args.authorId) where.authorId = args.authorId;

      return prisma.post.findMany({
        where,
        take: args.limit,
        skip: args.offset,
        orderBy: { createdAt: 'desc' },
      });
    },

    post: async (_parent, args) => {
      return prisma.post.findUnique({ where: { id: args.id } });
    },

    searchPosts: async (_parent, args) => {
      return prisma.post.findMany({
        where: {
          OR: [
            { title: { contains: args.query, mode: 'insensitive' } },
            { body: { contains: args.query, mode: 'insensitive' } },
          ],
        },
      });
    },
  },

  Mutation: {
    createPost: async (_parent, args, context) => {
      if (!context.userId) throw new Error('Authentication required');

      return prisma.post.create({
        data: {
          ...args.input,
          authorId: context.userId,
        },
      });
    },

    updatePost: async (_parent, args, context) => {
      const post = await prisma.post.findUnique({ where: { id: args.id } });
      if (!post) throw new Error('Post not found');
      if (post.authorId !== context.userId) throw new Error('Not authorized');

      return prisma.post.update({
        where: { id: args.id },
        data: args.input,
      });
    },

    deletePost: async (_parent, args, context) => {
      const post = await prisma.post.findUnique({ where: { id: args.id } });
      if (!post) throw new Error('Post not found');
      if (post.authorId !== context.userId) throw new Error('Not authorized');

      await prisma.post.delete({ where: { id: args.id } });
      return true;
    },
  },

  // Field-level resolvers for relationships
  User: {
    posts: async (parent) => {
      return prisma.post.findMany({ where: { authorId: parent.id } });
    },
  },

  Post: {
    author: async (parent) => {
      return prisma.user.findUnique({ where: { id: parent.authorId } });
    },
    comments: async (parent) => {
      return prisma.comment.findMany({ where: { postId: parent.id } });
    },
  },

  Comment: {
    author: async (parent) => {
      return prisma.user.findUnique({ where: { id: parent.authorId } });
    },
    post: async (parent) => {
      return prisma.post.findUnique({ where: { id: parent.postId } });
    },
  },
};
```

## Resolver Execution Flow

```
query {
  user(id: "1") {        <-- Query.user resolver runs
    name                  <-- returned from Query.user
    posts {               <-- User.posts resolver runs
      title               <-- returned from User.posts
      author {            <-- Post.author resolver runs (for EACH post)
        name
      }
    }
  }
}

Execution:
1. Query.user(_, { id: "1" }) -> User
2. User.posts(user) -> [Post, Post, ...]
3. For each Post: Post.author(post) -> User   <-- N+1 problem!
```

## Error Handling in GraphQL

```typescript
import { GraphQLError } from 'graphql';

const resolvers = {
  Mutation: {
    createPost: async (_parent, args, context) => {
      if (!context.userId) {
        throw new GraphQLError('You must be logged in', {
          extensions: {
            code: 'UNAUTHENTICATED',
            http: { status: 401 },
          },
        });
      }

      try {
        return await prisma.post.create({ data: args.input });
      } catch (err) {
        if (err.code === 'P2002') {
          throw new GraphQLError('A post with this title already exists', {
            extensions: { code: 'CONFLICT' },
          });
        }
        throw new GraphQLError('Failed to create post', {
          extensions: { code: 'INTERNAL_SERVER_ERROR' },
        });
      }
    },
  },
};
```

GraphQL errors are returned in the `errors` array alongside partial `data`:

```json
{
  "data": { "createPost": null },
  "errors": [
    {
      "message": "You must be logged in",
      "extensions": { "code": "UNAUTHENTICATED" },
      "path": ["createPost"]
    }
  ]
}
```

## GraphQL vs REST: When to Choose GraphQL

| Factor | Use GraphQL | Use REST |
|--------|------------|----------|
| Multiple frontends with different data needs | Yes | Maybe |
| Complex, nested data relationships | Yes | Harder |
| Simple CRUD operations | Overkill | Yes |
| File upload/download | Harder | Yes |
| Caching | More complex | Easy (HTTP cache) |
| Team familiarity | Learning curve | Well understood |

5.2.2.body:
# Apollo Server: Resolvers, Context, and Directives

Apollo Server is the most popular GraphQL server implementation for Node.js. This lesson covers advanced resolver patterns, context management for authentication, and custom directives for reusable schema logic.

## Resolver Architecture

Every field in a GraphQL schema has a resolver. Resolvers follow a specific signature:

```typescript
type Resolver = (
  parent: any,       // Result from the parent resolver
  args: any,         // Arguments passed to the field
  context: Context,  // Shared per-request context
  info: GraphQLResolveInfo // Query AST and metadata
) => any;
```

### Default Resolvers

Apollo uses default resolvers for scalar fields. If your `User` type has a `name` field, and the parent resolver returns `{ name: 'Alice' }`, Apollo auto-resolves `name` without an explicit resolver.

```typescript
// You do NOT need this:
const resolvers = {
  User: {
    name: (parent) => parent.name, // Apollo does this automatically
  },
};

// You ONLY need resolvers for:
// 1. Computed fields
// 2. Relationship fields that require DB queries
// 3. Fields that transform the parent's data
```

## Context: Per-Request Shared State

Context is created fresh for each request. It is the place for:
- Authenticated user info
- Database connections
- DataLoaders
- Request-scoped services

```typescript
import { ApolloServer } from '@apollo/server';
import { expressMiddleware } from '@apollo/server/express4';
import jwt from 'jsonwebtoken';

interface Context {
  userId: string | null;
  userRole: string | null;
  prisma: PrismaClient;
  loaders: ReturnType<typeof createLoaders>;
}

const server = new ApolloServer<Context>({
  typeDefs,
  resolvers,
});

await server.start();

app.use(
  '/graphql',
  express.json(),
  expressMiddleware(server, {
    context: async ({ req }): Promise<Context> => {
      // Extract user from JWT token
      let userId: string | null = null;
      let userRole: string | null = null;

      const token = req.headers.authorization?.replace('Bearer ', '');
      if (token) {
        try {
          const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
          userId = decoded.sub;
          userRole = decoded.role;
        } catch {
          // Invalid token - continue as unauthenticated
        }
      }

      return {
        userId,
        userRole,
        prisma,
        loaders: createLoaders(prisma),
      };
    },
  })
);
```

### Using Context in Resolvers

```typescript
const resolvers = {
  Query: {
    me: async (_parent, _args, context: Context) => {
      if (!context.userId) return null;
      return context.prisma.user.findUnique({
        where: { id: context.userId },
      });
    },

    adminDashboard: async (_parent, _args, context: Context) => {
      if (context.userRole !== 'ADMIN') {
        throw new GraphQLError('Admin access required', {
          extensions: { code: 'FORBIDDEN' },
        });
      }
      // return dashboard data
    },
  },

  Mutation: {
    createPost: async (_parent, args, context: Context) => {
      requireAuth(context);
      return context.prisma.post.create({
        data: { ...args.input, authorId: context.userId },
      });
    },
  },
};

function requireAuth(context: Context): asserts context is Context & { userId: string } {
  if (!context.userId) {
    throw new GraphQLError('Authentication required', {
      extensions: { code: 'UNAUTHENTICATED' },
    });
  }
}
```

## Custom Directives

Directives add reusable behavior to schema fields. They are declared in SDL and implemented in code.

### @auth Directive

```graphql
# Schema
directive @auth(requires: Role = USER) on FIELD_DEFINITION

enum Role {
  USER
  ADMIN
  MODERATOR
}

type Query {
  publicPosts: [Post!]!
  me: User @auth
  adminUsers: [User!]! @auth(requires: ADMIN)
}

type Mutation {
  createPost(input: CreatePostInput!): Post! @auth
  deleteUser(id: ID!): Boolean! @auth(requires: ADMIN)
}
```

Implementation using schema transforms:

```typescript
import { mapSchema, getDirective, MapperKind } from '@graphql-tools/utils';
import { defaultFieldResolver, GraphQLSchema } from 'graphql';

function authDirectiveTransformer(schema: GraphQLSchema): GraphQLSchema {
  return mapSchema(schema, {
    [MapperKind.OBJECT_FIELD]: (fieldConfig) => {
      const authDirective = getDirective(schema, fieldConfig, 'auth')?.[0];
      if (!authDirective) return fieldConfig;

      const requiredRole = authDirective.requires || 'USER';
      const originalResolve = fieldConfig.resolve || defaultFieldResolver;

      fieldConfig.resolve = async (parent, args, context, info) => {
        if (!context.userId) {
          throw new GraphQLError('Authentication required', {
            extensions: { code: 'UNAUTHENTICATED' },
          });
        }

        const roleHierarchy = ['USER', 'MODERATOR', 'ADMIN'];
        const userLevel = roleHierarchy.indexOf(context.userRole);
        const requiredLevel = roleHierarchy.indexOf(requiredRole);

        if (userLevel < requiredLevel) {
          throw new GraphQLError(`Role '${requiredRole}' required`, {
            extensions: { code: 'FORBIDDEN' },
          });
        }

        return originalResolve(parent, args, context, info);
      };

      return fieldConfig;
    },
  });
}

// Apply the transformer
import { makeExecutableSchema } from '@graphql-tools/schema';

let schema = makeExecutableSchema({ typeDefs, resolvers });
schema = authDirectiveTransformer(schema);

const server = new ApolloServer({ schema });
```

### @deprecated Directive (Built-in)

```graphql
type User {
  id: ID!
  name: String! @deprecated(reason: "Use firstName and lastName instead")
  firstName: String!
  lastName: String!
}
```

### @cacheControl Directive

Apollo's built-in caching directive:

```graphql
type Post @cacheControl(maxAge: 60) {
  id: ID!
  title: String!
  body: String!
  viewCount: Int! @cacheControl(maxAge: 10) # changes frequently
}

type Query {
  publicPosts: [Post!]! @cacheControl(maxAge: 300)
  me: User @cacheControl(maxAge: 0, scope: PRIVATE)
}
```

## Apollo Server Plugins

Plugins hook into the request lifecycle:

```typescript
import { ApolloServerPlugin } from '@apollo/server';

const loggingPlugin: ApolloServerPlugin<Context> = {
  async requestDidStart(requestContext) {
    const start = Date.now();
    const operationName = requestContext.request.operationName;

    console.log(`GraphQL request started: ${operationName}`);

    return {
      async didResolveOperation(ctx) {
        console.log(`Operation: ${ctx.operation.operation} ${operationName}`);
      },

      async didEncounterErrors(ctx) {
        for (const err of ctx.errors) {
          console.error(`GraphQL Error: ${err.message}`, {
            path: err.path,
            code: err.extensions?.code,
          });
        }
      },

      async willSendResponse() {
        const duration = Date.now() - start;
        console.log(`GraphQL response: ${operationName} (${duration}ms)`);
      },
    };
  },
};

// Query complexity plugin
const complexityPlugin: ApolloServerPlugin<Context> = {
  async requestDidStart() {
    return {
      async didResolveOperation(ctx) {
        // Calculate complexity based on query depth and fields
        const complexity = calculateComplexity(ctx.document, ctx.operation);
        if (complexity > 1000) {
          throw new GraphQLError(
            `Query complexity ${complexity} exceeds maximum of 1000`,
            { extensions: { code: 'QUERY_TOO_COMPLEX' } }
          );
        }
      },
    };
  },
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [loggingPlugin, complexityPlugin],
});
```

## Query Depth Limiting

```typescript
import depthLimit from 'graphql-depth-limit';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [depthLimit(5)], // Max 5 levels of nesting
});
```

## Organizing Resolvers

For large schemas, split resolvers by type:

```
src/
  graphql/
    schema.graphql
    resolvers/
      index.ts       # merges all resolvers
      user.ts
      post.ts
      comment.ts
    directives/
      auth.ts
      cache.ts
    loaders/
      index.ts
```

```typescript
// resolvers/index.ts
import { merge } from 'lodash';
import { userResolvers } from './user';
import { postResolvers } from './post';
import { commentResolvers } from './comment';
import { dateTimeResolver } from './scalars';

export const resolvers = merge(
  userResolvers,
  postResolvers,
  commentResolvers,
  { DateTime: dateTimeResolver }
);
```

## Custom Scalars

```typescript
import { GraphQLScalarType, Kind } from 'graphql';

const dateTimeResolver = new GraphQLScalarType({
  name: 'DateTime',
  description: 'ISO 8601 date-time string',
  serialize(value: Date) {
    return value.toISOString();
  },
  parseValue(value: string) {
    const date = new Date(value);
    if (isNaN(date.getTime())) throw new Error('Invalid DateTime');
    return date;
  },
  parseLiteral(ast) {
    if (ast.kind === Kind.STRING) {
      const date = new Date(ast.value);
      if (isNaN(date.getTime())) throw new Error('Invalid DateTime');
      return date;
    }
    throw new Error('DateTime must be a string');
  },
});
```

5.2.3.body:
# Subscriptions, DataLoaders, and N+1 Prevention

This lesson tackles two critical GraphQL challenges: real-time data with subscriptions and the infamous N+1 query problem solved by DataLoader.

## The N+1 Problem

Consider this query:

```graphql
query {
  posts(limit: 10) {
    title
    author {
      name
    }
  }
}
```

Without DataLoader, this executes:

```
1 query:  SELECT * FROM posts LIMIT 10
10 queries: SELECT * FROM users WHERE id = 1
            SELECT * FROM users WHERE id = 2
            SELECT * FROM users WHERE id = 1  (duplicate!)
            SELECT * FROM users WHERE id = 3
            ...etc
= 11 queries total (1 + N)
```

## DataLoader: Batching and Caching

DataLoader collects all individual requests within a single tick of the event loop and batches them into one query.

```typescript
import DataLoader from 'dataloader';
import { PrismaClient } from '@prisma/client';

// Batch function: receives array of keys, returns array of results in same order
async function batchUsers(prisma: PrismaClient, ids: readonly string[]) {
  const users = await prisma.user.findMany({
    where: { id: { in: [...ids] } },
  });

  // IMPORTANT: Return results in the SAME ORDER as the input ids
  const userMap = new Map(users.map(u => [u.id, u]));
  return ids.map(id => userMap.get(id) || null);
}

// Create loaders (one per request!)
function createLoaders(prisma: PrismaClient) {
  return {
    userLoader: new DataLoader<string, User | null>(
      (ids) => batchUsers(prisma, ids)
    ),

    postsByAuthorLoader: new DataLoader<string, Post[]>(
      async (authorIds) => {
        const posts = await prisma.post.findMany({
          where: { authorId: { in: [...authorIds] } },
        });
        const grouped = new Map<string, Post[]>();
        for (const post of posts) {
          if (!grouped.has(post.authorId)) grouped.set(post.authorId, []);
          grouped.get(post.authorId)!.push(post);
        }
        return authorIds.map(id => grouped.get(id) || []);
      }
    ),

    commentsByPostLoader: new DataLoader<string, Comment[]>(
      async (postIds) => {
        const comments = await prisma.comment.findMany({
          where: { postId: { in: [...postIds] } },
        });
        const grouped = new Map<string, Comment[]>();
        for (const comment of comments) {
          if (!grouped.has(comment.postId)) grouped.set(comment.postId, []);
          grouped.get(comment.postId)!.push(comment);
        }
        return postIds.map(id => grouped.get(id) || []);
      }
    ),
  };
}
```

### Integrating DataLoader with Context

```typescript
app.use(
  '/graphql',
  express.json(),
  expressMiddleware(server, {
    context: async ({ req }) => {
      // Create NEW loaders for each request (caching is per-request)
      return {
        userId: extractUserId(req),
        prisma,
        loaders: createLoaders(prisma),
      };
    },
  })
);

// Use loaders in resolvers
const resolvers = {
  Post: {
    author: (post, _args, context) => {
      return context.loaders.userLoader.load(post.authorId);
    },
    comments: (post, _args, context) => {
      return context.loaders.commentsByPostLoader.load(post.id);
    },
  },
  User: {
    posts: (user, _args, context) => {
      return context.loaders.postsByAuthorLoader.load(user.id);
    },
  },
};
```

Now the same query executes:

```
1 query: SELECT * FROM posts LIMIT 10
1 query: SELECT * FROM users WHERE id IN (1, 2, 3)  -- batched & deduplicated!
= 2 queries total
```

### DataLoader Execution Flow

```
Tick 1: Resolve post[0].author -> loader.load('user-1')
         Resolve post[1].author -> loader.load('user-2')
         Resolve post[2].author -> loader.load('user-1')  // cached!
         ...all 10 posts queue loads

Tick 2: DataLoader executes batch function
         batchUsers(['user-1', 'user-2', 'user-3'])
         One SQL query, results distributed to all waiting resolvers
```

## GraphQL Subscriptions

Subscriptions enable real-time, server-pushed updates over WebSocket connections.

```graphql
type Subscription {
  postCreated: Post!
  commentAdded(postId: ID!): Comment!
  userStatusChanged(userId: ID!): UserStatus!
}

type UserStatus {
  userId: ID!
  online: Boolean!
  lastSeen: DateTime!
}
```

### Setting Up Subscriptions with graphql-ws

```typescript
import { ApolloServer } from '@apollo/server';
import { expressMiddleware } from '@apollo/server/express4';
import { createServer } from 'http';
import { WebSocketServer } from 'ws';
import { useServer } from 'graphql-ws/lib/use/ws';
import { makeExecutableSchema } from '@graphql-tools/schema';
import { PubSub } from 'graphql-subscriptions';

const pubsub = new PubSub();

const schema = makeExecutableSchema({ typeDefs, resolvers });

// HTTP server for queries and mutations
const app = express();
const httpServer = createServer(app);

// WebSocket server for subscriptions
const wsServer = new WebSocketServer({
  server: httpServer,
  path: '/graphql',
});

const wsServerCleanup = useServer(
  {
    schema,
    context: async (ctx) => {
      // Authenticate WebSocket connections
      const token = ctx.connectionParams?.authorization as string;
      const userId = token ? verifyToken(token) : null;
      return { userId, prisma, loaders: createLoaders(prisma) };
    },
    onConnect: async (ctx) => {
      console.log('Client connected');
      // Return false to reject the connection
    },
    onDisconnect: async (ctx) => {
      console.log('Client disconnected');
    },
  },
  wsServer
);

const server = new ApolloServer({
  schema,
  plugins: [
    {
      async serverWillStart() {
        return {
          async drainServer() {
            await wsServerCleanup.dispose();
          },
        };
      },
    },
  ],
});

await server.start();
app.use('/graphql', express.json(), expressMiddleware(server, { context: async ({ req }) => ({ /* ... */ }) }));
httpServer.listen(4000);
```

### Subscription Resolvers with PubSub

```typescript
const EVENTS = {
  POST_CREATED: 'POST_CREATED',
  COMMENT_ADDED: 'COMMENT_ADDED',
  USER_STATUS_CHANGED: 'USER_STATUS_CHANGED',
};

const resolvers = {
  Subscription: {
    postCreated: {
      subscribe: () => pubsub.asyncIterableIterator([EVENTS.POST_CREATED]),
    },

    commentAdded: {
      subscribe: (_parent, args) => {
        // Filter: only get comments for a specific post
        return pubsub.asyncIterableIterator([`${EVENTS.COMMENT_ADDED}.${args.postId}`]);
      },
    },

    userStatusChanged: {
      subscribe: (_parent, args) => {
        return pubsub.asyncIterableIterator([`${EVENTS.USER_STATUS_CHANGED}.${args.userId}`]);
      },
    },
  },

  Mutation: {
    createPost: async (_parent, args, context) => {
      const post = await context.prisma.post.create({
        data: { ...args.input, authorId: context.userId },
        include: { author: true },
      });

      // Publish event to all subscribers
      pubsub.publish(EVENTS.POST_CREATED, { postCreated: post });

      return post;
    },

    addComment: async (_parent, args, context) => {
      const comment = await context.prisma.comment.create({
        data: {
          text: args.text,
          postId: args.postId,
          authorId: context.userId,
        },
        include: { author: true },
      });

      // Publish to post-specific channel
      pubsub.publish(`${EVENTS.COMMENT_ADDED}.${args.postId}`, {
        commentAdded: comment,
      });

      return comment;
    },
  },
};
```

### Production PubSub with Redis

The in-memory `PubSub` only works for single-server setups. For production, use Redis:

```typescript
import { RedisPubSub } from 'graphql-redis-subscriptions';
import Redis from 'ioredis';

const pubsub = new RedisPubSub({
  publisher: new Redis({ host: 'localhost', port: 6379 }),
  subscriber: new Redis({ host: 'localhost', port: 6379 }),
});
```

### Filtering Subscriptions

Use `withFilter` for fine-grained subscription filtering:

```typescript
import { withFilter } from 'graphql-subscriptions';

const resolvers = {
  Subscription: {
    commentAdded: {
      subscribe: withFilter(
        () => pubsub.asyncIterableIterator([EVENTS.COMMENT_ADDED]),
        (payload, variables) => {
          // Only send to clients watching this specific post
          return payload.commentAdded.postId === variables.postId;
        }
      ),
    },
  },
};
```

## Performance Monitoring

Track N+1 issues with query logging:

```typescript
// Prisma query logging
const prisma = new PrismaClient({
  log: [
    { emit: 'event', level: 'query' },
  ],
});

prisma.$on('query', (e) => {
  console.log(`Query: ${e.query} (${e.duration}ms)`);
});
```

5.3.1.body:
# tRPC Fundamentals: Routers, Procedures, and Context

tRPC (TypeScript Remote Procedure Call) provides end-to-end type safety between your backend and frontend without code generation, schemas, or runtime validation overhead. If you control both the client and server in TypeScript, tRPC might be the most productive API layer available.

## Why tRPC?

```
REST / GraphQL workflow:
1. Define API schema/types
2. Implement server handlers
3. Generate client types (or write manually)
4. Keep everything in sync (manual effort)

tRPC workflow:
1. Write server procedures with TypeScript types
2. Import the type on the client
3. Done. Types are always in sync.
```

```
+------------------+          Type inference          +------------------+
|   tRPC Server    | -------------------------------->|   tRPC Client    |
|  (defines types) |    No codegen, no runtime cost   | (auto-complete!) |
+------------------+                                  +------------------+
```

## Setting Up tRPC

```typescript
// server/trpc.ts - Initialize tRPC
import { initTRPC, TRPCError } from '@trpc/server';
import { Context } from './context';

const t = initTRPC.context<Context>().create();

export const router = t.router;
export const publicProcedure = t.procedure;
export const middleware = t.middleware;
```

### Context Setup

```typescript
// server/context.ts
import { CreateExpressContextOptions } from '@trpc/server/adapters/express';
import { PrismaClient } from '@prisma/client';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

export interface Context {
  prisma: PrismaClient;
  userId: string | null;
  userRole: string | null;
}

export function createContext({ req }: CreateExpressContextOptions): Context {
  let userId: string | null = null;
  let userRole: string | null = null;

  const token = req.headers.authorization?.replace('Bearer ', '');
  if (token) {
    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
      userId = decoded.sub;
      userRole = decoded.role;
    } catch {
      // Invalid token
    }
  }

  return { prisma, userId, userRole };
}
```

## Procedures

tRPC has three types of procedures:

- **query** - Read operations (like GET)
- **mutation** - Write operations (like POST/PUT/DELETE)
- **subscription** - Real-time updates (like WebSocket)

```typescript
// server/routers/user.ts
import { z } from 'zod';
import { router, publicProcedure } from '../trpc';
import { TRPCError } from '@trpc/server';

export const userRouter = router({
  // Query: fetch a user by ID
  getById: publicProcedure
    .input(z.object({ id: z.string().uuid() }))
    .query(async ({ input, ctx }) => {
      const user = await ctx.prisma.user.findUnique({
        where: { id: input.id },
      });
      if (!user) {
        throw new TRPCError({
          code: 'NOT_FOUND',
          message: `User with id '${input.id}' not found`,
        });
      }
      return user;
    }),

  // Query: list users with pagination
  list: publicProcedure
    .input(
      z.object({
        limit: z.number().min(1).max(100).default(20),
        cursor: z.string().uuid().optional(),
      })
    )
    .query(async ({ input, ctx }) => {
      const users = await ctx.prisma.user.findMany({
        take: input.limit + 1,
        ...(input.cursor && {
          cursor: { id: input.cursor },
          skip: 1,
        }),
        orderBy: { createdAt: 'desc' },
      });

      let nextCursor: string | undefined;
      if (users.length > input.limit) {
        const nextItem = users.pop();
        nextCursor = nextItem!.id;
      }

      return { users, nextCursor };
    }),

  // Mutation: create a user
  create: publicProcedure
    .input(
      z.object({
        email: z.string().email(),
        name: z.string().min(2).max(100),
        bio: z.string().max(500).optional(),
      })
    )
    .mutation(async ({ input, ctx }) => {
      return ctx.prisma.user.create({ data: input });
    }),

  // Mutation: update a user
  update: publicProcedure
    .input(
      z.object({
        id: z.string().uuid(),
        name: z.string().min(2).max(100).optional(),
        bio: z.string().max(500).optional(),
      })
    )
    .mutation(async ({ input, ctx }) => {
      const { id, ...data } = input;
      return ctx.prisma.user.update({ where: { id }, data });
    }),
});
```

## Routers and Merging

```typescript
// server/routers/post.ts
export const postRouter = router({
  getById: publicProcedure
    .input(z.object({ id: z.string().uuid() }))
    .query(async ({ input, ctx }) => {
      return ctx.prisma.post.findUnique({
        where: { id: input.id },
        include: { author: true, comments: true },
      });
    }),

  create: publicProcedure
    .input(
      z.object({
        title: z.string().min(5).max(200),
        body: z.string().min(50),
        tags: z.array(z.string()).max(10).optional(),
      })
    )
    .mutation(async ({ input, ctx }) => {
      if (!ctx.userId) {
        throw new TRPCError({ code: 'UNAUTHORIZED' });
      }
      return ctx.prisma.post.create({
        data: { ...input, authorId: ctx.userId },
      });
    }),

  delete: publicProcedure
    .input(z.object({ id: z.string().uuid() }))
    .mutation(async ({ input, ctx }) => {
      if (!ctx.userId) {
        throw new TRPCError({ code: 'UNAUTHORIZED' });
      }
      const post = await ctx.prisma.post.findUnique({ where: { id: input.id } });
      if (!post || post.authorId !== ctx.userId) {
        throw new TRPCError({ code: 'FORBIDDEN' });
      }
      await ctx.prisma.post.delete({ where: { id: input.id } });
      return { success: true };
    }),
});

// server/routers/index.ts - App Router
import { router } from '../trpc';
import { userRouter } from './user';
import { postRouter } from './post';

export const appRouter = router({
  user: userRouter,
  post: postRouter,
});

// Export type for client usage
export type AppRouter = typeof appRouter;
```

## Middleware

tRPC middleware runs before procedure execution, similar to Express middleware:

```typescript
import { middleware, publicProcedure } from '../trpc';

// Auth middleware
const isAuthenticated = middleware(async ({ ctx, next }) => {
  if (!ctx.userId) {
    throw new TRPCError({ code: 'UNAUTHORIZED' });
  }
  return next({
    ctx: {
      ...ctx,
      userId: ctx.userId, // now guaranteed non-null
    },
  });
});

// Protected procedure (requires authentication)
export const protectedProcedure = publicProcedure.use(isAuthenticated);

// Admin middleware
const isAdmin = middleware(async ({ ctx, next }) => {
  if (ctx.userRole !== 'ADMIN') {
    throw new TRPCError({ code: 'FORBIDDEN' });
  }
  return next({ ctx });
});

export const adminProcedure = protectedProcedure.use(isAdmin);

// Logging middleware
const logMiddleware = middleware(async ({ path, type, next }) => {
  const start = Date.now();
  const result = await next();
  const duration = Date.now() - start;
  console.log(`${type} ${path} - ${duration}ms`);
  return result;
});

export const loggedProcedure = publicProcedure.use(logMiddleware);
```

### Using Protected Procedures

```typescript
export const postRouter = router({
  // Anyone can read
  getById: publicProcedure
    .input(z.object({ id: z.string() }))
    .query(/* ... */),

  // Must be logged in to create
  create: protectedProcedure
    .input(z.object({ title: z.string(), body: z.string() }))
    .mutation(async ({ input, ctx }) => {
      // ctx.userId is guaranteed non-null here!
      return ctx.prisma.post.create({
        data: { ...input, authorId: ctx.userId },
      });
    }),

  // Must be admin to delete any post
  adminDelete: adminProcedure
    .input(z.object({ id: z.string() }))
    .mutation(async ({ input, ctx }) => {
      await ctx.prisma.post.delete({ where: { id: input.id } });
      return { success: true };
    }),
});
```

## Connecting to Express

```typescript
// server/index.ts
import express from 'express';
import * as trpcExpress from '@trpc/server/adapters/express';
import { appRouter } from './routers';
import { createContext } from './context';

const app = express();

app.use(
  '/trpc',
  trpcExpress.createExpressMiddleware({
    router: appRouter,
    createContext,
    onError: ({ error, path }) => {
      console.error(`tRPC error on ${path}:`, error.message);
    },
  })
);

app.listen(4000, () => console.log('tRPC server on port 4000'));
```

## Error Handling

tRPC has built-in error codes that map to HTTP status codes:

```typescript
import { TRPCError } from '@trpc/server';

// Available codes:
// BAD_REQUEST (400)
// UNAUTHORIZED (401)
// FORBIDDEN (403)
// NOT_FOUND (404)
// METHOD_NOT_SUPPORTED (405)
// TIMEOUT (408)
// CONFLICT (409)
// PRECONDITION_FAILED (412)
// PAYLOAD_TOO_LARGE (413)
// UNPROCESSABLE_CONTENT (422)
// TOO_MANY_REQUESTS (429)
// CLIENT_CLOSED_REQUEST (499)
// INTERNAL_SERVER_ERROR (500)

throw new TRPCError({
  code: 'NOT_FOUND',
  message: 'Post not found',
  cause: originalError, // optional, for debugging
});
```

5.3.2.body:
# Input Validation with Zod and End-to-End Type Safety

tRPC's killer feature is end-to-end type safety. When you define a Zod schema on the server, the client automatically knows the exact shape of inputs and outputs -- with full IDE auto-complete, no code generation needed.

## Zod as the Validation Layer

Zod schemas serve double duty in tRPC: runtime validation AND TypeScript type inference.

```typescript
import { z } from 'zod';

// Define the schema once
const createUserSchema = z.object({
  email: z.string().email('Invalid email format'),
  name: z.string().min(2, 'Name must be at least 2 characters').max(100),
  password: z.string()
    .min(8, 'Password must be at least 8 characters')
    .regex(/[A-Z]/, 'Must contain at least one uppercase letter')
    .regex(/[0-9]/, 'Must contain at least one number'),
  role: z.enum(['USER', 'ADMIN']).default('USER'),
  bio: z.string().max(500).optional(),
  tags: z.array(z.string()).max(10).default([]),
});

// Infer the TypeScript type from the schema
type CreateUserInput = z.infer<typeof createUserSchema>;
// Result: {
//   email: string;
//   name: string;
//   password: string;
//   role: 'USER' | 'ADMIN';
//   bio?: string;
//   tags: string[];
// }
```

## Complex Zod Schemas for tRPC

```typescript
// Pagination input (reusable)
const paginationSchema = z.object({
  limit: z.number().int().min(1).max(100).default(20),
  cursor: z.string().uuid().optional(),
});

// Filter schema with operators
const postFilterSchema = z.object({
  status: z.enum(['DRAFT', 'PUBLISHED', 'ARCHIVED']).optional(),
  authorId: z.string().uuid().optional(),
  tags: z.array(z.string()).optional(),
  createdAfter: z.coerce.date().optional(),
  createdBefore: z.coerce.date().optional(),
  search: z.string().min(1).max(200).optional(),
});

// Combine schemas
const listPostsInput = paginationSchema.merge(postFilterSchema);

// Use in router
export const postRouter = router({
  list: publicProcedure
    .input(listPostsInput)
    .query(async ({ input, ctx }) => {
      const where: any = {};
      if (input.status) where.status = input.status;
      if (input.authorId) where.authorId = input.authorId;
      if (input.tags) where.tags = { hasSome: input.tags };
      if (input.search) {
        where.OR = [
          { title: { contains: input.search, mode: 'insensitive' } },
          { body: { contains: input.search, mode: 'insensitive' } },
        ];
      }
      if (input.createdAfter || input.createdBefore) {
        where.createdAt = {};
        if (input.createdAfter) where.createdAt.gte = input.createdAfter;
        if (input.createdBefore) where.createdAt.lte = input.createdBefore;
      }

      const posts = await ctx.prisma.post.findMany({
        where,
        take: input.limit + 1,
        ...(input.cursor && { cursor: { id: input.cursor }, skip: 1 }),
        orderBy: { createdAt: 'desc' },
        include: { author: { select: { id: true, name: true } } },
      });

      let nextCursor: string | undefined;
      if (posts.length > input.limit) {
        nextCursor = posts.pop()!.id;
      }

      return { posts, nextCursor };
    }),
});
```

## Output Validation

tRPC also supports output schemas to guarantee the response shape:

```typescript
const userOutputSchema = z.object({
  id: z.string(),
  email: z.string(),
  name: z.string(),
  // password is NOT included -- filtered from output
  createdAt: z.date(),
});

export const userRouter = router({
  getById: publicProcedure
    .input(z.object({ id: z.string().uuid() }))
    .output(userOutputSchema) // <-- validates and strips output
    .query(async ({ input, ctx }) => {
      const user = await ctx.prisma.user.findUnique({
        where: { id: input.id },
      });
      if (!user) throw new TRPCError({ code: 'NOT_FOUND' });
      return user; // password will be stripped by output validation
    }),
});
```

## The Client Side: Full Type Safety

```typescript
// client/trpc.ts
import { createTRPCClient, httpBatchLink } from '@trpc/client';
import type { AppRouter } from '../server/routers'; // TYPE-ONLY import

const trpc = createTRPCClient<AppRouter>({
  links: [
    httpBatchLink({
      url: 'http://localhost:4000/trpc',
      headers: () => ({
        authorization: `Bearer ${getToken()}`,
      }),
    }),
  ],
});

// Full auto-complete and type checking!
async function example() {
  // Type-safe query
  const user = await trpc.user.getById.query({ id: '123' });
  console.log(user.name);     // TypeScript knows this is string
  console.log(user.password);  // ERROR: property 'password' does not exist

  // Type-safe mutation
  const newPost = await trpc.post.create.mutate({
    title: 'Hello',       // Required (min 5 chars)
    body: 'World...',     // Required (min 50 chars)
    // tags: 123,          // ERROR: expected string[]
  });

  // Type-safe pagination
  const posts = await trpc.post.list.query({
    limit: 10,
    status: 'PUBLISHED',
    // status: 'INVALID',  // ERROR: not in enum
  });
}
```

## Batch Requests

tRPC automatically batches multiple simultaneous requests:

```typescript
// These three calls are batched into ONE HTTP request
const [user, posts, comments] = await Promise.all([
  trpc.user.getById.query({ id: '1' }),
  trpc.post.list.query({ limit: 5 }),
  trpc.comment.recent.query({ limit: 10 }),
]);
// HTTP: POST /trpc/user.getById,post.list,comment.recent
```

## Error Handling on the Client

```typescript
import { TRPCClientError } from '@trpc/client';

try {
  await trpc.user.create.mutate({
    email: 'invalid',
    name: 'A',
    password: 'weak',
  });
} catch (error) {
  if (error instanceof TRPCClientError) {
    console.log(error.message);      // Error message
    console.log(error.data?.code);    // 'BAD_REQUEST'

    // Access Zod validation errors
    if (error.data?.zodError) {
      const fieldErrors = error.data.zodError.fieldErrors;
      // { email: ['Invalid email format'], name: ['Name must be...'] }
      for (const [field, messages] of Object.entries(fieldErrors)) {
        console.log(`${field}: ${messages.join(', ')}`);
      }
    }
  }
}
```

## Transformers for Complex Types

By default, tRPC serializes data as JSON, which loses Date objects and other non-JSON types. Use superjson:

```typescript
import superjson from 'superjson';

// Server
const t = initTRPC.context<Context>().create({
  transformer: superjson,
});

// Client
const trpc = createTRPCClient<AppRouter>({
  links: [
    httpBatchLink({
      url: 'http://localhost:4000/trpc',
      transformer: superjson,
    }),
  ],
});

// Now Date objects, Maps, Sets, BigInt, etc. work correctly
const post = await trpc.post.getById.query({ id: '1' });
console.log(post.createdAt instanceof Date); // true!
```

## Type Inference Utilities

tRPC provides helper types for extracting input/output types:

```typescript
import type { inferRouterInputs, inferRouterOutputs } from '@trpc/server';
import type { AppRouter } from '../server/routers';

type RouterInputs = inferRouterInputs<AppRouter>;
type RouterOutputs = inferRouterOutputs<AppRouter>;

// Get specific procedure types
type CreateUserInput = RouterInputs['user']['create'];
type UserOutput = RouterOutputs['user']['getById'];

// Use in components, forms, etc.
function UserForm(props: { onSubmit: (data: CreateUserInput) => void }) {
  // ...
}
```

5.3.3.body:
# tRPC with Express and NestJS

tRPC integrates with existing Express and NestJS applications, so you do not need to rewrite your entire API. You can mount tRPC alongside REST routes and migrate incrementally.

## tRPC with Express

### Basic Integration

```typescript
import express from 'express';
import cors from 'cors';
import * as trpcExpress from '@trpc/server/adapters/express';
import { appRouter } from './routers';
import { createContext } from './context';

const app = express();

// Regular Express middleware
app.use(cors());
app.use(express.json());

// Regular REST routes (existing API)
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.get('/api/legacy/users', async (req, res) => {
  // Old REST endpoint still works
  res.json({ users: [] });
});

// Mount tRPC alongside REST
app.use(
  '/trpc',
  trpcExpress.createExpressMiddleware({
    router: appRouter,
    createContext,
    onError: ({ error, path, type }) => {
      console.error(`tRPC ${type} error on '${path}':`, error.message);
    },
  })
);

app.listen(4000, () => {
  console.log('Server running on port 4000');
  console.log('REST: http://localhost:4000/api/*');
  console.log('tRPC: http://localhost:4000/trpc/*');
});
```

### Sharing Express Middleware with tRPC

You can reuse existing Express middleware (auth, rate limiting, etc.) in tRPC through context:

```typescript
import rateLimit from 'express-rate-limit';

// Apply rate limiting to tRPC routes
const trpcLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
});

app.use('/trpc', trpcLimiter);
app.use(
  '/trpc',
  trpcExpress.createExpressMiddleware({ router: appRouter, createContext })
);
```

### Using Express Request in Context

```typescript
import { CreateExpressContextOptions } from '@trpc/server/adapters/express';

export function createContext({ req, res }: CreateExpressContextOptions) {
  // Access Express req/res in context
  return {
    req,
    res,
    prisma,
    userId: extractUserId(req),
    ip: req.ip,
    userAgent: req.headers['user-agent'],
  };
}
```

## tRPC with NestJS

Integrating tRPC with NestJS requires a bit more setup since NestJS has its own DI system:

### Option 1: Mount as Express Middleware

```typescript
// trpc/trpc.module.ts
import { Module, NestModule, MiddlewareConsumer } from '@nestjs/common';
import * as trpcExpress from '@trpc/server/adapters/express';
import { appRouter } from './routers';
import { PrismaService } from '../prisma/prisma.service';

@Module({})
export class TrpcModule implements NestModule {
  constructor(private prisma: PrismaService) {}

  configure(consumer: MiddlewareConsumer) {
    consumer
      .apply(
        trpcExpress.createExpressMiddleware({
          router: appRouter,
          createContext: ({ req }) => ({
            prisma: this.prisma,
            userId: (req as any).userId || null,
          }),
        })
      )
      .forRoutes('/trpc');
  }
}
```

### Option 2: NestJS-tRPC Integration

```typescript
// Using @nest-rpc/trpc or custom integration
// trpc/trpc.service.ts
import { Injectable } from '@nestjs/common';
import { initTRPC, TRPCError } from '@trpc/server';
import { z } from 'zod';
import { PrismaService } from '../prisma/prisma.service';
import { UserService } from '../user/user.service';

interface Context {
  prisma: PrismaService;
  userId: string | null;
}

@Injectable()
export class TrpcService {
  private t = initTRPC.context<Context>().create();

  constructor(
    private prisma: PrismaService,
    private userService: UserService,
  ) {}

  get appRouter() {
    return this.t.router({
      user: this.t.router({
        getById: this.t.procedure
          .input(z.object({ id: z.string() }))
          .query(async ({ input }) => {
            return this.userService.findById(input.id);
          }),

        list: this.t.procedure
          .input(z.object({ limit: z.number().default(20) }))
          .query(async ({ input }) => {
            return this.userService.findAll(input.limit);
          }),
      }),
    });
  }

  createContext(req: any): Context {
    return {
      prisma: this.prisma,
      userId: req.userId || null,
    };
  }
}
```

### Full NestJS Controller Approach

```typescript
// trpc/trpc.controller.ts
import { All, Controller, Req, Res } from '@nestjs/common';
import { Request, Response } from 'express';
import { resolveHTTPResponse } from '@trpc/server/http';
import { TrpcService } from './trpc.service';

@Controller('trpc')
export class TrpcController {
  constructor(private trpcService: TrpcService) {}

  @All('*')
  async handler(@Req() req: Request, @Res() res: Response) {
    const path = req.path.replace('/trpc/', '');
    const context = this.trpcService.createContext(req);

    const response = await resolveHTTPResponse({
      router: this.trpcService.appRouter,
      req: {
        method: req.method,
        headers: req.headers,
        query: req.query,
        body: req.body,
      },
      path,
      createContext: () => context,
    });

    if (response.status) res.status(response.status);
    for (const [key, value] of Object.entries(response.headers || {})) {
      if (typeof value !== 'undefined') {
        res.setHeader(key, value);
      }
    }
    res.json(JSON.parse(response.body || '{}'));
  }
}
```

## Incremental Migration Strategy

You do not have to replace REST with tRPC all at once:

```
Phase 1: Add tRPC alongside existing REST API
+-------------------------------------------+
|  Express / NestJS App                     |
|  /api/*     -> REST controllers (existing)|
|  /trpc/*    -> tRPC router (new features) |
+-------------------------------------------+

Phase 2: New features use tRPC, migrate old ones gradually
+-------------------------------------------+
|  /api/legacy/*  -> Old REST endpoints     |
|  /trpc/*        -> tRPC (growing)         |
+-------------------------------------------+

Phase 3: Full tRPC (optional)
+-------------------------------------------+
|  /trpc/*        -> All procedures         |
+-------------------------------------------+
```

```typescript
// Migration helper: wrap existing service methods
class UserServiceAdapter {
  constructor(private userService: UserService) {}

  createTrpcRouter(t: ReturnType<typeof initTRPC.create>) {
    return t.router({
      getById: t.procedure
        .input(z.object({ id: z.string() }))
        .query(({ input }) => this.userService.findById(input.id)),

      create: t.procedure
        .input(createUserSchema)
        .mutation(({ input }) => this.userService.create(input)),

      update: t.procedure
        .input(updateUserSchema)
        .mutation(({ input }) => this.userService.update(input.id, input)),

      delete: t.procedure
        .input(z.object({ id: z.string() }))
        .mutation(({ input }) => this.userService.delete(input.id)),
    });
  }
}
```

## Testing tRPC Procedures

```typescript
import { createCallerFactory } from '@trpc/server';
import { appRouter } from './routers';

const createCaller = createCallerFactory(appRouter);

describe('User Router', () => {
  let caller: ReturnType<typeof createCaller>;

  beforeEach(() => {
    caller = createCaller({
      prisma: prismaMock,
      userId: 'test-user-id',
      userRole: 'USER',
    });
  });

  it('should get a user by id', async () => {
    prismaMock.user.findUnique.mockResolvedValue(mockUser);
    const result = await caller.user.getById({ id: mockUser.id });
    expect(result).toEqual(mockUser);
  });

  it('should throw NOT_FOUND for missing user', async () => {
    prismaMock.user.findUnique.mockResolvedValue(null);
    await expect(
      caller.user.getById({ id: 'nonexistent' })
    ).rejects.toThrow('NOT_FOUND');
  });

  it('should validate input', async () => {
    await expect(
      caller.user.create({ email: 'invalid', name: '', password: '123' })
    ).rejects.toThrow(); // Zod validation error
  });
});
```

5.4.1.body:
# Protocol Buffers and Service Definitions

Protocol Buffers (protobuf) is Google's language-neutral data serialization format used by gRPC. It is smaller, faster, and more strictly typed than JSON. Understanding protobuf is the foundation for building gRPC services.

## Why Protocol Buffers?

```
JSON:  { "name": "Alice", "age": 30, "active": true }
       46 bytes, text parsing required

Protobuf: [binary encoding]
       ~15 bytes, direct memory mapping, schema-enforced
```

Protobuf advantages:
- 3-10x smaller than JSON
- 20-100x faster serialization/deserialization
- Strongly typed with a schema (`.proto` file)
- Backward/forward compatible with field numbering
- Code generation for any language

## Proto3 Syntax

```protobuf
// user.proto
syntax = "proto3";

package myapp.user;

// Import other proto files
import "google/protobuf/timestamp.proto";
import "google/protobuf/empty.proto";

// Message definitions (like TypeScript interfaces)
message User {
  string id = 1;              // field number 1
  string email = 2;           // field number 2
  string name = 3;
  string bio = 4;
  Role role = 5;
  google.protobuf.Timestamp created_at = 6;
  repeated string tags = 7;   // array of strings
  optional string avatar_url = 8; // explicitly optional
}

// Enums
enum Role {
  ROLE_UNSPECIFIED = 0;  // proto3 requires 0 value
  ROLE_USER = 1;
  ROLE_ADMIN = 2;
  ROLE_MODERATOR = 3;
}

// Nested messages
message Address {
  string street = 1;
  string city = 2;
  string state = 3;
  string zip = 4;
  string country = 5;
}

message UserProfile {
  User user = 1;
  Address address = 2;
  map<string, string> metadata = 3;  // key-value pairs
}
```

### Field Numbers Are Critical

Field numbers are the wire identifier. They must:
- Never be reused after deletion (use `reserved`)
- Stay stable across versions
- Use 1-15 for frequently used fields (1 byte encoding)
- Use 16-2047 for less common fields (2 byte encoding)

```protobuf
message Post {
  reserved 4, 8;              // these numbers cannot be reused
  reserved "old_field_name";  // these names cannot be reused

  string id = 1;
  string title = 2;
  string body = 3;
  // field 4 was deleted (old 'summary' field)
  string author_id = 5;
  PostStatus status = 6;
}
```

## Service Definitions

gRPC services are defined in proto files:

```protobuf
// service.proto
syntax = "proto3";

package myapp.blog;

import "google/protobuf/empty.proto";
import "google/protobuf/timestamp.proto";

// Request/Response messages
message CreatePostRequest {
  string title = 1;
  string body = 2;
  repeated string tags = 3;
}

message GetPostRequest {
  string id = 1;
}

message ListPostsRequest {
  int32 page_size = 1;
  string page_token = 2;  // cursor for pagination
  PostStatus status_filter = 3;
}

message ListPostsResponse {
  repeated Post posts = 1;
  string next_page_token = 2;
  int32 total_count = 3;
}

message Post {
  string id = 1;
  string title = 2;
  string body = 3;
  string author_id = 4;
  PostStatus status = 5;
  repeated string tags = 6;
  google.protobuf.Timestamp created_at = 7;
  google.protobuf.Timestamp updated_at = 8;
}

message UpdatePostRequest {
  string id = 1;
  optional string title = 2;
  optional string body = 3;
  repeated string tags = 4;
  optional PostStatus status = 5;
}

message DeletePostRequest {
  string id = 1;
}

enum PostStatus {
  POST_STATUS_UNSPECIFIED = 0;
  POST_STATUS_DRAFT = 1;
  POST_STATUS_PUBLISHED = 2;
  POST_STATUS_ARCHIVED = 3;
}

// Service definition
service BlogService {
  // Unary RPC: one request, one response
  rpc CreatePost(CreatePostRequest) returns (Post);
  rpc GetPost(GetPostRequest) returns (Post);
  rpc UpdatePost(UpdatePostRequest) returns (Post);
  rpc DeletePost(DeletePostRequest) returns (google.protobuf.Empty);
  rpc ListPosts(ListPostsRequest) returns (ListPostsResponse);

  // Server streaming: one request, stream of responses
  rpc WatchPosts(ListPostsRequest) returns (stream Post);

  // Client streaming: stream of requests, one response
  rpc BatchCreatePosts(stream CreatePostRequest) returns (ListPostsResponse);

  // Bidirectional streaming: stream both ways
  rpc Chat(stream ChatMessage) returns (stream ChatMessage);
}

message ChatMessage {
  string sender_id = 1;
  string text = 2;
  google.protobuf.Timestamp timestamp = 3;
}
```

## Generating Code for Node.js

Use `grpc-tools` and `ts-proto` for TypeScript-friendly code generation:

```bash
npm install @grpc/grpc-js @grpc/proto-loader
# For code generation:
npm install -D grpc-tools grpc_tools_node_protoc_ts
# Or for ts-proto (better TypeScript support):
npm install -D ts-proto
```

### Using @grpc/proto-loader (Dynamic Loading)

```typescript
import * as grpc from '@grpc/grpc-js';
import * as protoLoader from '@grpc/proto-loader';

const packageDefinition = protoLoader.loadSync('./protos/service.proto', {
  keepCase: true,
  longs: String,
  enums: String,
  defaults: true,
  oneofs: true,
  includeDirs: ['./protos'],
});

const proto = grpc.loadPackageDefinition(packageDefinition) as any;
const BlogService = proto.myapp.blog.BlogService;
```

### Using ts-proto (Static Code Generation)

```bash
# Install protoc compiler and ts-proto
npx buf generate
# or directly:
protoc --plugin=./node_modules/.bin/protoc-gen-ts_proto \
  --ts_proto_out=./src/generated \
  --ts_proto_opt=outputServices=grpc-js \
  --ts_proto_opt=esModuleInterop=true \
  ./protos/service.proto
```

This generates TypeScript types and service interfaces:

```typescript
// generated/service.ts (auto-generated)
export interface Post {
  id: string;
  title: string;
  body: string;
  authorId: string;
  status: PostStatus;
  tags: string[];
  createdAt: Date | undefined;
  updatedAt: Date | undefined;
}

export interface BlogServiceServer extends grpc.UntypedServiceImplementation {
  createPost: grpc.handleUnaryCall<CreatePostRequest, Post>;
  getPost: grpc.handleUnaryCall<GetPostRequest, Post>;
  listPosts: grpc.handleUnaryCall<ListPostsRequest, ListPostsResponse>;
  watchPosts: grpc.handleServerStreamingCall<ListPostsRequest, Post>;
}
```

## Schema Evolution and Compatibility

Protobuf supports backward-compatible evolution:

```protobuf
// Version 1
message User {
  string id = 1;
  string name = 2;
}

// Version 2 (backward compatible)
message User {
  string id = 1;
  string name = 2;
  string email = 3;     // NEW: old clients ignore this
  int32 age = 4;        // NEW: old clients ignore this
}

// Version 3 (removing a field - use reserved)
message User {
  reserved 2;           // 'name' removed, number reserved
  reserved "name";
  string id = 1;
  string first_name = 5;
  string last_name = 6;
  string email = 3;
  int32 age = 4;
}
```

Rules for backward compatibility:
- Never change a field number
- Never change a field type
- Add new fields with new numbers
- Use `reserved` for removed fields
- Never reuse a field number

