## Schema Validation Testing

For simpler contract testing without Pact, validate responses against your OpenAPI schema:

```typescript
import Ajv from 'ajv';
import addFormats from 'ajv-formats';
import swaggerSpec from '../swagger.json';

const ajv = new Ajv({ allErrors: true });
addFormats(ajv);

// Extract schema from OpenAPI spec
function getResponseSchema(path: string, method: string, statusCode: number) {
  const pathSpec = swaggerSpec.paths[path]?.[method];
  return pathSpec?.responses?.[String(statusCode)]?.content?.['application/json']?.schema;
}

describe('API Response Contract Tests', () => {
  it('GET /api/users/:id matches the schema', async () => {
    const response = await request(app).get('/api/users/1').expect(200);
    const schema = getResponseSchema('/api/users/{id}', 'get', 200);
    const validate = ajv.compile(schema);
    const valid = validate(response.body);

    if (!valid) {
      console.error('Schema validation errors:', validate.errors);
    }
    expect(valid).toBe(true);
  });

  it('POST /api/users matches the schema', async () => {
    const response = await request(app)
      .post('/api/users')
      .send({ name: 'Test', email: 'test@test.com' })
      .expect(201);

    const schema = getResponseSchema('/api/users', 'post', 201);
    const validate = ajv.compile(schema);
    expect(validate(response.body)).toBe(true);
  });
});
```

