# Hexagonal Architecture: Ports and Adapters

Hexagonal Architecture (also called Ports and Adapters) organizes code so that business logic is completely isolated from external concerns like databases, HTTP frameworks, and third-party services. This makes your application testable, flexible, and technology-agnostic.

## The Core Idea

```
              +---------------------------+
              |      External World       |
              |  (HTTP, CLI, Messages)    |
              +----------+----------------+
                         |
                    [Driving Adapters]
                    (Controllers, CLI)
                         |
              +----------v----------------+
              |       Input Ports         |
              |     (Use Case interfaces) |
              +----------+----------------+
                         |
              +----------v----------------+
              |    APPLICATION CORE       |
              |                           |
              |  Domain Entities          |
              |  Business Rules           |
              |  Use Cases                |
              |                           |
              +----------+----------------+
                         |
              +----------v----------------+
              |      Output Ports         |
              |  (Repository interfaces)  |
              +----------+----------------+
                         |
                   [Driven Adapters]
                   (Prisma, Redis, S3)
                         |
              +----------v----------------+
              |      External World       |
              |  (DB, Cache, Email, etc)  |
              +---------------------------+
```

### Key Terminology

- **Ports**: Interfaces that define how the application communicates with the outside
  - **Input Ports** (Driving): How the outside calls the application (use cases)
  - **Output Ports** (Driven): How the application calls the outside (repositories, services)
- **Adapters**: Implementations of ports
  - **Driving Adapters**: Controllers, CLI commands, GraphQL resolvers
  - **Driven Adapters**: Database repositories, email senders, API clients

## Project Structure

```
src/
  domain/                    # Pure business logic (no dependencies)
    entities/
      post.entity.ts
      user.entity.ts
      comment.entity.ts
    value-objects/
      email.vo.ts
      money.vo.ts
    errors/
      domain.error.ts

  application/               # Use cases (depends only on domain)
    ports/
      input/                 # Input ports (use case interfaces)
        create-post.port.ts
        publish-post.port.ts
        get-post.port.ts
      output/                # Output ports (driven interfaces)
        post.repository.port.ts
        user.repository.port.ts
        notification.port.ts
        event-bus.port.ts
    use-cases/               # Use case implementations
      create-post.use-case.ts
      publish-post.use-case.ts
      get-post.use-case.ts

  infrastructure/            # Adapters (implement ports)
    adapters/
      driving/               # Input adapters
        rest/
          post.controller.ts
          user.controller.ts
        graphql/
          post.resolver.ts
        cli/
          seed.command.ts
      driven/                # Output adapters
        persistence/
          prisma-post.repository.ts
          prisma-user.repository.ts
          in-memory-post.repository.ts
        notification/
          email-notification.adapter.ts
          slack-notification.adapter.ts
        event/
          redis-event-bus.adapter.ts
    config/
      database.config.ts

  main.ts                    # Composition root (wires everything)
```

## Implementation

### Domain Layer (Zero Dependencies)

```typescript
// domain/entities/post.entity.ts
// NO imports from Prisma, Express, NestJS, etc.
export class Post {
  constructor(
    public readonly id: string,
    public title: string,
    public body: string,
    public status: PostStatus,
    public readonly authorId: string,
    public tags: string[],
    public readonly createdAt: Date,
    public updatedAt: Date,
    public publishedAt: Date | null,
  ) {}

  publish(): void {
    if (this.status !== PostStatus.DRAFT) {
      throw new DomainError('Only drafts can be published');
    }
    this.status = PostStatus.PUBLISHED;
    this.publishedAt = new Date();
    this.updatedAt = new Date();
  }

  isOwnedBy(userId: string): boolean {
    return this.authorId === userId;
  }
}
```

### Output Ports (Interfaces)

```typescript
// application/ports/output/post.repository.port.ts
// Defines what the application NEEDS from persistence
export interface PostRepositoryPort {
  findById(id: string): Promise<Post | null>;
  findAll(options: FindOptions): Promise<{ posts: Post[]; total: number }>;
  save(post: Post): Promise<Post>;
  update(id: string, data: Partial<Post>): Promise<Post>;
  delete(id: string): Promise<void>;
}

// application/ports/output/notification.port.ts
export interface NotificationPort {
  notifyUser(userId: string, message: string): Promise<void>;
  notifyFollowers(userId: string, message: string): Promise<void>;
}

// application/ports/output/event-bus.port.ts
export interface EventBusPort {
  publish(event: DomainEvent): Promise<void>;
}
```

### Input Ports (Use Case Interfaces)

```typescript
// application/ports/input/create-post.port.ts
export interface CreatePostPort {
  execute(command: CreatePostCommand): Promise<Post>;
}

export interface CreatePostCommand {
  title: string;
  body: string;
  tags: string[];
  authorId: string;
}
```

### Use Cases (Application Layer)

```typescript
// application/use-cases/create-post.use-case.ts
import { CreatePostPort, CreatePostCommand } from '../ports/input/create-post.port';
import { PostRepositoryPort } from '../ports/output/post.repository.port';
import { EventBusPort } from '../ports/output/event-bus.port';
import { Post, PostStatus } from '../../domain/entities/post.entity';

export class CreatePostUseCase implements CreatePostPort {
  constructor(
    private postRepo: PostRepositoryPort,   // Output port
    private eventBus: EventBusPort,         // Output port
  ) {}

  async execute(command: CreatePostCommand): Promise<Post> {
    const post = new Post(
      generateId(),
      command.title,
      command.body,
      PostStatus.DRAFT,
      command.authorId,
      command.tags,
      new Date(),
      new Date(),
      null,
    );

    const saved = await this.postRepo.save(post);
    await this.eventBus.publish(new PostCreatedEvent(saved));
    return saved;
  }
}

// application/use-cases/publish-post.use-case.ts
export class PublishPostUseCase implements PublishPostPort {
  constructor(
    private postRepo: PostRepositoryPort,
    private notifier: NotificationPort,
    private eventBus: EventBusPort,
  ) {}

  async execute(command: PublishPostCommand): Promise<Post> {
    const post = await this.postRepo.findById(command.postId);
    if (!post) throw new NotFoundError('Post', command.postId);
    if (!post.isOwnedBy(command.userId)) throw new ForbiddenError();

    post.publish(); // Domain logic

    const updated = await this.postRepo.update(post.id, {
      status: post.status,
      publishedAt: post.publishedAt,
    });

    await this.eventBus.publish(new PostPublishedEvent(updated));
    await this.notifier.notifyFollowers(post.authorId, `New post: ${post.title}`);

    return updated;
  }
}
```

### Driven Adapters (Implement Output Ports)

```typescript
// infrastructure/adapters/driven/persistence/prisma-post.repository.ts
import { PrismaClient } from '@prisma/client';
import { PostRepositoryPort } from '../../../../application/ports/output/post.repository.port';
import { Post } from '../../../../domain/entities/post.entity';

export class PrismaPostRepository implements PostRepositoryPort {
  constructor(private prisma: PrismaClient) {}

  async findById(id: string): Promise<Post | null> {
    const record = await this.prisma.post.findUnique({ where: { id } });
    return record ? this.toDomain(record) : null;
  }

  async save(post: Post): Promise<Post> {
    const record = await this.prisma.post.create({
      data: this.toPersistence(post),
    });
    return this.toDomain(record);
  }

  // Map between persistence and domain models
  private toDomain(record: any): Post {
    return new Post(
      record.id, record.title, record.body, record.status,
      record.authorId, record.tags, record.createdAt,
      record.updatedAt, record.publishedAt,
    );
  }

  private toPersistence(post: Post): any {
    return {
      id: post.id, title: post.title, body: post.body,
      status: post.status, authorId: post.authorId, tags: post.tags,
    };
  }

  // ... other methods
}

// infrastructure/adapters/driven/notification/email.adapter.ts
import { NotificationPort } from '../../../../application/ports/output/notification.port';

export class EmailNotificationAdapter implements NotificationPort {
  constructor(private emailClient: any) {}

  async notifyUser(userId: string, message: string): Promise<void> {
    const email = await this.lookupEmail(userId);
    await this.emailClient.send({ to: email, subject: 'Notification', body: message });
  }

  async notifyFollowers(userId: string, message: string): Promise<void> {
    // implementation
  }
}
```

### Driving Adapters (Call Input Ports)

```typescript
// infrastructure/adapters/driving/rest/post.controller.ts
import { CreatePostPort } from '../../../../application/ports/input/create-post.port';
import { PublishPostPort } from '../../../../application/ports/input/publish-post.port';

export class PostController {
  constructor(
    private createPostUseCase: CreatePostPort,
    private publishPostUseCase: PublishPostPort,
  ) {}

  async create(req: Request, res: Response) {
    const post = await this.createPostUseCase.execute({
      title: req.body.title,
      body: req.body.body,
      tags: req.body.tags || [],
      authorId: req.user.id,
    });
    res.status(201).json(post);
  }

  async publish(req: Request, res: Response) {
    const post = await this.publishPostUseCase.execute({
      postId: req.params.id,
      userId: req.user.id,
    });
    res.json(post);
  }
}
```

### Composition Root

```typescript
// main.ts - Wire everything together
const prisma = new PrismaClient();

// Create driven adapters
const postRepo = new PrismaPostRepository(prisma);
const notifier = new EmailNotificationAdapter(emailClient);
const eventBus = new RedisEventBus(redis);

// Create use cases
const createPost = new CreatePostUseCase(postRepo, eventBus);
const publishPost = new PublishPostUseCase(postRepo, notifier, eventBus);

// Create driving adapters
const postController = new PostController(createPost, publishPost);

// Mount routes
app.post('/api/posts', (req, res) => postController.create(req, res));
app.post('/api/posts/:id/publish', (req, res) => postController.publish(req, res));
```

## The Dependency Rule

```
Dependencies point INWARD:

  Infrastructure -> Application -> Domain

  Domain depends on NOTHING
  Application depends only on Domain
  Infrastructure depends on Application and Domain
```

Never import from infrastructure in domain or application layers.

5.7.2.body:
# Dependency Inversion in Practice

The Dependency Inversion Principle (DIP) states: high-level modules should not depend on low-level modules; both should depend on abstractions. This is the foundation of testable, flexible architecture.

## The Problem Without DIP

```typescript
// BAD: High-level depends on low-level
import { PrismaClient } from '@prisma/client';  // low-level detail
import nodemailer from 'nodemailer';            // low-level detail

class OrderService {
  private prisma = new PrismaClient();  // tightly coupled
  private mailer = nodemailer.createTransport(/* ... */); // tightly coupled

  async createOrder(data: any) {
    const order = await this.prisma.order.create({ data });  // can't test without DB
    await this.mailer.sendMail({ /* ... */ });  // sends real email in tests!
    return order;
  }
}
```

Problems:
- Cannot test without a real database
- Cannot test without sending real emails
- Cannot switch from Prisma to Drizzle without rewriting
- Cannot switch from nodemailer to SendGrid without rewriting

## The Solution: Depend on Abstractions

```
Without DIP:                    With DIP:
OrderService                    OrderService
    |                               |
    +-> PrismaClient            IOrderRepository <---+
    +-> nodemailer              IEmailService <---+   |
                                                  |   |
                           SendGridAdapter -------+   |
                           PrismaOrderRepo -----------+
```

```typescript
// GOOD: Both depend on abstractions

// 1. Define abstractions (interfaces)
interface IOrderRepository {
  create(data: CreateOrderData): Promise<Order>;
  findById(id: string): Promise<Order | null>;
  update(id: string, data: Partial<Order>): Promise<Order>;
}

interface IEmailService {
  send(to: string, subject: string, body: string): Promise<void>;
}

interface IPaymentGateway {
  charge(amount: number, paymentMethodId: string): Promise<PaymentResult>;
  refund(chargeId: string): Promise<RefundResult>;
}

// 2. High-level module depends on abstractions
class OrderService {
  constructor(
    private orderRepo: IOrderRepository,     // abstraction
    private emailService: IEmailService,     // abstraction
    private paymentGateway: IPaymentGateway, // abstraction
  ) {}

  async createOrder(userId: string, items: OrderItem[]): Promise<Order> {
    const order = await this.orderRepo.create({ userId, items, status: 'CREATED' });
    await this.emailService.send(userId, 'Order Created', `Order #${order.id}`);
    return order;
  }

  async payOrder(orderId: string, paymentMethodId: string): Promise<Order> {
    const order = await this.orderRepo.findById(orderId);
    if (!order) throw new NotFoundError('Order', orderId);

    const result = await this.paymentGateway.charge(order.total, paymentMethodId);
    if (!result.success) throw new PaymentError(result.error);

    return this.orderRepo.update(orderId, { status: 'PAID', chargeId: result.chargeId });
  }
}
```

## Implementing Adapters

```typescript
// Low-level: Prisma implementation
class PrismaOrderRepository implements IOrderRepository {
  constructor(private prisma: PrismaClient) {}

  async create(data: CreateOrderData): Promise<Order> {
    return this.prisma.order.create({ data });
  }
  async findById(id: string): Promise<Order | null> {
    return this.prisma.order.findUnique({ where: { id } });
  }
  async update(id: string, data: Partial<Order>): Promise<Order> {
    return this.prisma.order.update({ where: { id }, data });
  }
}

// Low-level: SendGrid implementation
class SendGridEmailService implements IEmailService {
  constructor(private apiKey: string) {}
  async send(to: string, subject: string, body: string): Promise<void> {
    // SendGrid API call
  }
}

// Low-level: Stripe implementation
class StripePaymentGateway implements IPaymentGateway {
  constructor(private stripe: Stripe) {}
  async charge(amount: number, paymentMethodId: string): Promise<PaymentResult> {
    const intent = await this.stripe.paymentIntents.create({
      amount: Math.round(amount * 100),
      currency: 'usd',
      payment_method: paymentMethodId,
      confirm: true,
    });
    return { success: true, chargeId: intent.id };
  }
  async refund(chargeId: string): Promise<RefundResult> {
    await this.stripe.refunds.create({ payment_intent: chargeId });
    return { success: true };
  }
}
```

## Testing with Fakes

```typescript
// Test doubles
class FakeOrderRepository implements IOrderRepository {
  private orders: Order[] = [];
  private counter = 1;

  async create(data: CreateOrderData): Promise<Order> {
    const order = { id: String(this.counter++), ...data, total: 0, createdAt: new Date() };
    this.orders.push(order);
    return order;
  }
  async findById(id: string): Promise<Order | null> {
    return this.orders.find(o => o.id === id) || null;
  }
  async update(id: string, data: Partial<Order>): Promise<Order> {
    const idx = this.orders.findIndex(o => o.id === id);
    this.orders[idx] = { ...this.orders[idx], ...data };
    return this.orders[idx];
  }
}

class FakeEmailService implements IEmailService {
  sentEmails: Array<{ to: string; subject: string; body: string }> = [];

  async send(to: string, subject: string, body: string): Promise<void> {
    this.sentEmails.push({ to, subject, body });
  }
}

class FakePaymentGateway implements IPaymentGateway {
  shouldFail = false;
  charges: Array<{ amount: number; id: string }> = [];

  async charge(amount: number, paymentMethodId: string): Promise<PaymentResult> {
    if (this.shouldFail) return { success: false, error: 'Card declined' };
    const id = `ch_${Date.now()}`;
    this.charges.push({ amount, id });
    return { success: true, chargeId: id };
  }
  async refund(chargeId: string): Promise<RefundResult> {
    return { success: true };
  }
}

// Tests are fast, isolated, and deterministic
describe('OrderService', () => {
  let service: OrderService;
  let orderRepo: FakeOrderRepository;
  let emailService: FakeEmailService;
  let paymentGateway: FakePaymentGateway;

  beforeEach(() => {
    orderRepo = new FakeOrderRepository();
    emailService = new FakeEmailService();
    paymentGateway = new FakePaymentGateway();
    service = new OrderService(orderRepo, emailService, paymentGateway);
  });

  it('sends confirmation email on order creation', async () => {
    await service.createOrder('user-1', [{ productId: 'p1', quantity: 2 }]);
    expect(emailService.sentEmails).toHaveLength(1);
    expect(emailService.sentEmails[0].to).toBe('user-1');
  });

  it('handles payment failure gracefully', async () => {
    const order = await service.createOrder('user-1', []);
    paymentGateway.shouldFail = true;
    await expect(service.payOrder(order.id, 'pm_123')).rejects.toThrow('Card declined');
  });
});
```

## NestJS Dependency Injection

NestJS's DI system makes dependency inversion natural:

```typescript
// Define injection tokens
export const ORDER_REPOSITORY = Symbol('ORDER_REPOSITORY');
export const EMAIL_SERVICE = Symbol('EMAIL_SERVICE');
export const PAYMENT_GATEWAY = Symbol('PAYMENT_GATEWAY');

// Module wiring
@Module({
  providers: [
    OrderService,
    {
      provide: ORDER_REPOSITORY,
      useClass: PrismaOrderRepository,
    },
    {
      provide: EMAIL_SERVICE,
      useFactory: (config: ConfigService) => {
        const provider = config.get('EMAIL_PROVIDER');
        if (provider === 'sendgrid') return new SendGridEmailService(config.get('SENDGRID_KEY'));
        if (provider === 'ses') return new SesEmailService(config.get('AWS_REGION'));
        return new ConsoleEmailService(); // dev fallback
      },
      inject: [ConfigService],
    },
    {
      provide: PAYMENT_GATEWAY,
      useClass: StripePaymentGateway,
    },
  ],
})
export class OrderModule {}

// Service uses injection tokens
@Injectable()
export class OrderService {
  constructor(
    @Inject(ORDER_REPOSITORY) private orderRepo: IOrderRepository,
    @Inject(EMAIL_SERVICE) private emailService: IEmailService,
    @Inject(PAYMENT_GATEWAY) private paymentGateway: IPaymentGateway,
  ) {}
}
```

## Manual DI (Without Framework)

You do not need a DI framework. Constructor injection works fine:

```typescript
// composition-root.ts
function createApp() {
  const prisma = new PrismaClient();
  const redis = new Redis();

  // Create driven adapters
  const orderRepo = new PrismaOrderRepository(prisma);
  const emailService = new SendGridEmailService(process.env.SENDGRID_KEY!);
  const paymentGateway = new StripePaymentGateway(stripe);
  const cacheService = new RedisCacheService(redis);

  // Create services (inject abstractions)
  const orderService = new OrderService(orderRepo, emailService, paymentGateway);
  const productService = new ProductService(productRepo, cacheService);

  // Create controllers (inject services)
  const orderController = new OrderController(orderService);
  const productController = new ProductController(productService);

  // Wire routes
  const app = express();
  app.post('/orders', (req, res) => orderController.create(req, res));
  app.get('/products', (req, res) => productController.list(req, res));

  return app;
}
```
